head.b:skin:
/* =============================================
   LigTV İzlesene - Modern Dark Sports Theme
   ============================================= */

/* === CSS VARIABLES === */
:root {
  --primary: #e8001a;
  --primary-dark: #b5001a;
  --accent: #ff4d00;
  --bg-deep: #0a0d12;
  --bg-card: #111722;
  --bg-elevated: #161d2b;
  --bg-border: #1e2840;
  --text-primary: #edf0f7;
  --text-secondary: #8b9ab5;
  --text-muted: #4a5568;
  --live-red: #ff0028;
  --gold: #ffc300;
  --font-display: 'Barlow Condensed', sans-serif;
  --font-body: 'Barlow', sans-serif;
  --radius: 8px;
  --radius-sm: 4px;
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
  --shadow-card: 0 2px 16px rgba(0,0,0,0.5);
  --glow-primary: 0 0 20px rgba(232,0,26,0.3);
}

/* === RESET === */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body {
  background: var(--bg-deep);
  color: var(--text-primary);
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: 400;
  line-height: 1.6;
  overflow-x: hidden;
}
img { max-width: 100%; height: auto; display: block; }
a { color: var(--primary); text-decoration: none; transition: all 0.2s ease; }
a:visited { color: var(--primary); }
a:hover { color: #ff3355; }
ul, ol { list-style: none; }
h1,h2,h3,h4,h5,h6 { font-family: var(--font-display); font-weight: 700; line-height: 1.2; color: var(--text-primary); }
.section, .widget { margin: 0; padding: 0; }
.quickedit { display: none !important; }
.clear { clear: both; }
.post-feeds, .feed-links { display: none; }
#layout ul { display: none; }
hr { border: none; border-top: 1px solid var(--bg-border); margin: 20px 0; }

/* === PRELOADER === */
#preloader {
  position: fixed; inset: 0; z-index: 9999;
  background: var(--bg-deep);
  display: flex; align-items: center; justify-content: center;
}
.preload-inner {
  display: flex; flex-direction: column; align-items: center; gap: 20px;
}
.preload-logo {
  font-family: var(--font-display);
  font-size: 2.5rem; font-weight: 800; letter-spacing: 2px;
  color: var(--primary);
  animation: pulse-logo 1s ease-in-out infinite alternate;
}
@keyframes pulse-logo {
  from { opacity: 1; text-shadow: 0 0 30px rgba(232,0,26,0.8); }
  to { opacity: 0.5; text-shadow: none; }
}
.preload-bar {
  width: 200px; height: 3px; background: var(--bg-border); border-radius: 2px; overflow: hidden;
}
.preload-bar::after {
  content: ''; display: block; width: 60%; height: 100%;
  background: linear-gradient(90deg, var(--primary), var(--accent));
  animation: loading-bar 1.2s ease-in-out infinite;
}
@keyframes loading-bar {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(250%); }
}

/* === 404 ERROR === */
#error404 {
  position: fixed; inset: 0; z-index: 9999;
  background: var(--bg-deep);
  display: flex; align-items: center; justify-content: center;
  text-align: center;
}
#error-text { padding: 40px; }
#error-text span {
  display: block; font-family: var(--font-display);
  font-size: clamp(6rem, 20vw, 12rem); font-weight: 800;
  color: var(--primary); line-height: 1;
  text-shadow: var(--glow-primary);
}
#error-text h2 { font-size: 2rem; margin: 10px 0 20px; color: var(--text-secondary); }
#error-text a {
  display: inline-flex; align-items: center; gap: 8px;
  background: var(--primary); color: #fff;
  padding: 12px 28px; border-radius: var(--radius);
  font-family: var(--font-display); font-size: 1.1rem; font-weight: 700;
  letter-spacing: 1px; text-transform: uppercase;
  transition: all 0.3s; box-shadow: var(--glow-primary);
}
#error-text a:hover { background: var(--primary-dark); transform: translateY(-2px); }

/* === LAYOUT WRAPPER === */
#outer-wrapper { max-width: 1080px; margin: 0 auto; padding: 0 16px; overflow: visible; }

/* Anasayfa: içerik + sidebar yan yana */
.bwrapsite-content { display: flex; gap: 24px; align-items: flex-start; }
.content-area { flex: 1; min-width: 0; }
#sidebar-wrapper { width: 300px; flex-shrink: 0; }
.sidebar-area { width: 300px; }

/* Makale ve kanal sayfaları: içerik TAM GENİŞLİK, sidebar alta */
body.item-page .bwrapsite-content,
body.static_page .bwrapsite-content {
  display: grid !important;
  grid-template-columns: 1fr 280px !important;
  gap: 24px !important;
}
body.item-page .content-area,
body.static_page .content-area {
  width: 100% !important;
  min-width: 0 !important;
}

/* Tablet: sidebar alta al */
@media (max-width: 960px) {
  .bwrapsite-content { flex-direction: column !important; }
  #sidebar-wrapper { width: 100% !important; }
  .sidebar-area { width: 100% !important; }
  body.item-page .bwrapsite-content,
  body.static_page .bwrapsite-content {
    grid-template-columns: 1fr !important;
  }
}

/* === PLAYER İFRAME - Kanal sayfaları === */
body.static_page .post-body iframe,
body.static_page .post-body embed {
  width: 100% !important;
  height: 540px !important;
  display: block !important;
  border: none !important;
}
@media (max-width: 900px) { body.static_page .post-body iframe { height: 380px !important; } }
@media (max-width: 600px) { body.static_page .post-body iframe { height: 250px !important; } }
@media (max-width: 400px) { body.static_page .post-body iframe { height: 200px !important; } }

/* === TOP HEADER / NAVBAR === */
.site-navbar {
  background: var(--bg-card);
  border-bottom: 1px solid var(--bg-border);
  position: sticky; top: 0; z-index: 500;
  box-shadow: 0 2px 20px rgba(0,0,0,0.6);
}
.navbar-inner {
  max-width: 1080px; margin: 0 auto; padding: 0 16px;
  display: flex; align-items: center; justify-content: space-between;
  height: 64px;
}
#logo {
  display: flex; align-items: center;
  font-family: var(--font-display); font-size: 1.6rem; font-weight: 800;
  color: var(--text-primary); letter-spacing: 1px;
  text-transform: uppercase;
}
#logo img { max-height: 48px; width: auto; }
#logo .Header { display: flex; align-items: center; }
#logo .Header h1 { font-size: 1.5rem; color: var(--text-primary); margin: 0; }
#logo .Header h1 a { color: var(--text-primary); }
#logo .description { display: none; }
.logo-badge {
  display: inline-block; background: var(--primary);
  color: #fff; font-size: 0.6rem; font-weight: 800; letter-spacing: 2px;
  padding: 2px 6px; border-radius: 3px; margin-left: 8px;
  text-transform: uppercase; vertical-align: middle;
}

/* === MAIN NAV === */
#main-nav { display: flex; align-items: center; }
#main-nav .menu { display: flex; gap: 4px; }
#main-nav li { position: relative; }
#main-nav > .menu > li > a {
  display: flex; align-items: center; gap: 6px;
  padding: 8px 14px; border-radius: var(--radius-sm);
  color: var(--text-secondary); font-family: var(--font-display);
  font-size: 0.85rem; font-weight: 600; letter-spacing: 0.8px;
  text-transform: uppercase; white-space: nowrap;
  transition: all 0.2s;
}
#main-nav > .menu > li > a:hover,
#main-nav .current-menu-item > a {
  color: var(--text-primary);
  background: rgba(232,0,26,0.12);
}
#main-nav .current-menu-item > a { color: var(--primary); }

/* Dropdown */
#main-nav ul li ul {
  display: none; position: absolute; top: 100%; left: 0;
  background: var(--bg-card); border: 1px solid var(--bg-border);
  border-radius: var(--radius); min-width: 200px;
  box-shadow: var(--shadow); z-index: 200;
}
#main-nav ul li:hover > ul { display: block; }
#main-nav ul li ul li a {
  display: block; padding: 10px 16px;
  color: var(--text-secondary); font-size: 0.85rem; font-weight: 500;
}
#main-nav ul li ul li a:hover { color: var(--primary); background: rgba(232,0,26,0.08); }

/* Search */
#search-bar { position: relative; }
input#sq {
  background: var(--bg-elevated); color: var(--text-primary);
  border: 1px solid var(--bg-border); border-radius: 30px;
  padding: 8px 40px 8px 16px; font-size: 0.85rem;
  font-family: var(--font-body); width: 200px;
  transition: all 0.2s; outline: none;
}
input#sq:focus { border-color: var(--primary); width: 240px; background: var(--bg-card); }
input#sq::placeholder { color: var(--text-muted); }
#searchsubmit { display: none; }
.search-form-icon { position: absolute; right: 14px; top: 50%; transform: translateY(-50%); color: var(--text-muted); font-size: 14px; }

/* Mobile nav */
#menu-icon {
  display: none; width: 36px; height: 28px; cursor: pointer;
  flex-direction: column; justify-content: space-between; padding: 3px 0;
}
#menu-icon span { display: block; height: 2px; background: var(--text-primary); border-radius: 2px; transition: all 0.3s; }

/* === AD SLOT / TOP CHANNEL SECTION === */
#adpost2 { margin: 20px 0; }
#header-ad { width: 100%; }

/* === CHANNEL LIST (Live Channels Section) === */
.channels { margin-bottom: 20px; }
.channels .title {
  font-family: var(--font-display); font-size: 1.2rem; font-weight: 800;
  letter-spacing: 2px; text-transform: uppercase; color: var(--text-primary);
  display: flex; align-items: center; gap: 10px;
  margin-bottom: 12px; padding: 0;
}
.channels .title::before {
  content: ''; display: inline-block; width: 4px; height: 20px;
  background: var(--primary); border-radius: 2px;
}
.channels .channel-list {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 10px;
  background: transparent !important;
  padding: 0 !important;
}
.channels .channel-list li {
  background: var(--bg-card) !important;
  border: 1px solid var(--bg-border);
  border-radius: var(--radius);
  display: flex; align-items: center; justify-content: space-between;
  padding: 12px 14px !important;
  transition: all 0.25s;
  margin: 0 !important;
}
.channels .channel-list li:hover {
  border-color: var(--primary);
  background: var(--bg-elevated) !important;
  transform: translateY(-2px);
  box-shadow: 0 4px 20px rgba(232,0,26,0.2);
}
.channels .channel-list__left { display: flex; align-items: center; }
.channels .channel-list__left a img {
  width: 80px !important; height: auto; max-width: 80px !important;
  opacity: 0.85; filter: brightness(1.1); object-fit: contain;
}
.channels .channel-list__left a { min-height: auto !important; line-height: normal !important; }

/* Live Button */
.btn.btn-secondary {
  display: inline-flex; align-items: center; gap: 6px;
  background: rgba(232,0,26,0.15) !important;
  border: 1px solid var(--primary) !important;
  color: var(--primary) !important;
  font-family: var(--font-display); font-size: 0.75rem;
  font-weight: 700; letter-spacing: 1px; text-transform: uppercase;
  padding: 6px 12px; border-radius: 4px;
  white-space: nowrap; transition: all 0.2s;
}
.btn.btn-secondary:hover {
  background: var(--primary) !important;
  color: #fff !important;
  box-shadow: var(--glow-primary);
}
.live-badge__icon {
  display: inline-block; width: 7px; height: 7px;
  background: var(--live-red); border-radius: 50%;
  animation: live-pulse 1.5s ease-in-out infinite;
  flex-shrink: 0;
}
@keyframes live-pulse {
  0%, 100% { opacity: 1; box-shadow: 0 0 0 0 rgba(255,0,40,0.7); }
  50% { opacity: 0.7; box-shadow: 0 0 0 4px rgba(255,0,40,0); }
}

/* === MATCH SCHEDULE (Yayın Akışı) === */
.matches { margin-bottom: 20px; }
.matches ul { margin: 0 !important; padding: 0 !important; display: flex; flex-direction: column; gap: 4px; }
.matches ul li {
  background: var(--bg-card) !important;
  border: 1px solid var(--bg-border) !important;
  border-radius: var(--radius) !important;
  overflow: hidden; transition: all 0.25s; margin: 0 !important;
}
.matches ul li:hover { border-color: rgba(232,0,26,0.4) !important; background: var(--bg-elevated) !important; }
.matches-top {
  background: linear-gradient(90deg, var(--primary), #940010) !important;
  color: #fff !important; padding: 10px 16px !important;
  border-radius: var(--radius) !important;
  font-family: var(--font-display) !important; font-size: 0.85rem !important;
  font-weight: 700 !important; letter-spacing: 1.5px; text-transform: uppercase;
  display: flex; align-items: center;
  margin-bottom: 0 !important;
}
.matches-top span { color: var(--gold) !important; }
.m-col {
  display: flex; align-items: center; padding: 12px 16px;
  cursor: pointer; gap: 12px;
}
.m-col span:nth-child(1) {
  background: var(--primary) !important;
  color: #fff !important; font-family: var(--font-display);
  font-size: 1rem !important; font-weight: 800;
  padding: 4px 12px !important; border-radius: var(--radius-sm) !important;
  white-space: nowrap; flex-shrink: 0; float: none !important;
  width: auto !important; height: auto !important;
}
.m-col p2:nth-child(2) {
  flex: 1; font-weight: 500; color: var(--text-primary) !important;
  font-size: 0.95rem !important; float: none !important;
  width: auto !important; height: auto !important;
  padding: 0 !important; margin: 0 !important;
}
.m-col span:nth-child(3) {
  float: none !important; margin: 0 !important; margin-left: auto !important;
  width: 22px !important; height: 22px !important;
  border: 1px solid var(--bg-border) !important; border-radius: 50% !important;
  color: var(--text-muted) !important; display: flex !important;
  align-items: center; justify-content: center; flex-shrink: 0;
  transition: all 0.2s;
}
.m-col span:nth-child(4) {
  float: none !important; padding: 0 !important;
  font-family: var(--font-display); font-size: 0.7rem; font-weight: 700;
  letter-spacing: 1px; text-transform: uppercase;
  color: var(--text-muted) !important;
  background: var(--bg-elevated); border: 1px solid var(--bg-border);
  border-radius: var(--radius-sm); padding: 3px 8px !important;
  flex-shrink: 0;
}
.m-col-open {
  display: none;
  padding: 12px 16px; border-top: 1px solid var(--bg-border);
  background: var(--bg-elevated);
  flex-wrap: wrap; gap: 8px;
}
.m-col-open a {
  display: inline-flex; align-items: center; gap: 6px;
  background: rgba(232,0,26,0.1); border: 1px solid rgba(232,0,26,0.3) !important;
  color: var(--primary) !important; border-radius: var(--radius-sm);
  padding: 6px 14px !important; font-size: 0.8rem; font-weight: 600;
  transition: all 0.2s; margin: 0 !important;
}
.m-col-open a:hover { background: var(--primary) !important; color: #fff !important; }

/* === POSTS GRID === */
.blog-posts { overflow: hidden; }
.post-outer {
  background: var(--bg-card) !important;
  border: 1px solid var(--bg-border) !important;
  border-radius: var(--radius) !important;
  overflow: hidden; transition: all 0.3s;
  display: inline-block;
  margin-right: 3% !important; margin-bottom: 20px !important;
  float: left !important; height: auto !important;
  box-shadow: var(--shadow-card);
  vertical-align: top;
}
.post-outer:hover {
  border-color: rgba(232,0,26,0.4) !important;
  transform: translateY(-4px); box-shadow: 0 8px 32px rgba(0,0,0,0.6);
}
.odd { margin-right: 0 !important; }
.post { height: inherit; }

/* Post Image */
.post-image {
  width: 100%; overflow: hidden; background: var(--bg-elevated);
  aspect-ratio: 16/9; position: relative;
}
.post-image img {
  width: 100% !important; height: 100% !important;
  object-fit: cover !important;
  transition: transform 0.5s ease;
}
.post-outer:hover .post-image img { transform: scale(1.06); }

/* Label Badge */
.label-info { padding: 10px 12px 0; }
.label-info a {
  display: inline-block; background: rgba(232,0,26,0.15);
  border: 1px solid rgba(232,0,26,0.3); color: var(--primary) !important;
  font-size: 0.65rem; font-weight: 700; letter-spacing: 1.5px;
  text-transform: uppercase; padding: 3px 8px;
  border-radius: 3px; bottom: auto !important; margin: 0 !important;
  box-shadow: none !important;
}
.label-info a:nth-child(n+3) { display: none; }

/* Post Data */
.postdata { padding: 12px; }
h2.post-title, h1.post-title {
  font-family: var(--font-display) !important;
  font-size: 1.05rem !important; font-weight: 700 !important;
  color: var(--text-primary) !important; line-height: 1.3 !important;
  margin: 0 !important; max-height: none !important;
  display: -webkit-box !important; -webkit-line-clamp: 2 !important;
  -webkit-box-orient: vertical !important; overflow: hidden !important;
}
h2.post-title a, h1.post-title a { color: var(--text-primary) !important; }
h2.post-title a:hover, h1.post-title a:hover { color: var(--primary) !important; }

/* Post Info Bottom */
.postdata2 {
  padding: 8px 12px; border-top: 1px solid var(--bg-border);
  background: transparent; position: static !important;
  overflow: hidden; width: auto !important;
}
.post-info {
  display: flex; align-items: center; gap: 12px;
  font-size: 0.75rem; color: var(--text-muted); font-weight: 500;
  float: none !important; line-height: normal !important;
}
.post-info .fa { color: var(--primary); margin-right: 4px; }
.post-info a { color: var(--text-muted) !important; }
.share-item.share { display: none; }
.readmore2 { display: none; }

/* === SINGLE POST === */
body .post.hentry {
  background: var(--bg-card) !important;
  border: 1px solid var(--bg-border) !important;
  border-radius: var(--radius) !important;
}
h1.post-title {
  font-size: 2rem !important; padding: 24px !important;
  -webkit-line-clamp: initial !important; max-height: none !important;
  border-bottom: 1px solid var(--bg-border); margin-bottom: 0 !important;
}
.post-body {
  color: var(--text-secondary) !important; line-height: 1.7 !important;
  font-size: 1rem !important; padding: 20px 24px !important;
}
.post-info.single-info {
  padding: 12px 24px; background: var(--bg-elevated);
  border-top: 1px solid var(--bg-border);
  border-bottom: 1px solid var(--bg-border);
  margin-bottom: 0 !important;
}

/* Share buttons (single post) */
.sharepost { padding: 20px 24px; border-top: 1px solid var(--bg-border); overflow: hidden; margin: 0; }
.sharepost ul { display: flex; gap: 8px; justify-content: center; padding: 0; }
.sharepost li { float: none; margin: 0 !important; width: auto !important; }
.sharepost li a {
  display: flex; align-items: center; gap: 8px;
  padding: 10px 18px !important; border-radius: var(--radius-sm) !important;
  font-family: var(--font-display); font-size: 0.8rem; font-weight: 700;
  letter-spacing: 0.5px; text-transform: uppercase; color: #fff !important;
}
.sharepost li a .fa { float: none !important; padding: 0 !important; background: none !important; }
.sharepost li .twitter { background: #1da1f2 !important; }
.sharepost li .facebook { background: #1877f2 !important; }
.sharepost li .linkedin { background: #0a66c2 !important; }
.sharepost li .pinterest { background: #e60023 !important; }

/* Breadcrumbs */
.breadcrumbs {
  background: var(--bg-card); border: 1px solid var(--bg-border);
  border-radius: var(--radius); padding: 12px 16px;
  margin-bottom: 16px; font-size: 0.8rem; color: var(--text-muted);
  display: flex; align-items: center; flex-wrap: wrap; gap: 6px;
}
.breadcrumbs a { color: var(--text-muted); }
.breadcrumbs a:hover { color: var(--primary); }
.breadcrumbs span:first-child a { color: var(--primary); }
.breadcrumbs .fa-angle-right { color: var(--text-muted); font-size: 10px; }

/* Pagination */
.showpage, .showpageNum, .showpagePoint, .showpageOf {
  display: inline-block; padding: 8px 14px;
  background: var(--bg-card); border: 1px solid var(--bg-border);
  border-radius: var(--radius-sm); color: var(--text-secondary);
  font-size: 0.8rem; font-weight: 600; margin: 0 3px; transition: all 0.2s;
}
.showpagePoint { background: var(--primary) !important; border-color: var(--primary) !important; color: #fff !important; }
.showpage a:hover, .showpageNum a:hover, .showpagePoint:hover {
  background: var(--primary) !important; border-color: var(--primary) !important; color: #fff !important;
}
#blog-pager { text-align: center; padding: 20px 0; clear: both; }

/* Pager (single post) */
.pager { padding: 20px 24px; border-top: 1px solid var(--bg-border); overflow: hidden; }
.pager-left, .pager-right {
  width: 46% !important; background: var(--bg-elevated);
  border: 1px solid var(--bg-border); border-radius: var(--radius);
  padding: 12px 16px; transition: all 0.2s; height: auto !important;
}
.pager-left:hover, .pager-right:hover { border-color: var(--primary); }
.pager-title-left { font-family: var(--font-display); font-size: 1rem; font-weight: 700; color: var(--text-primary); display: block; margin-bottom: 4px; }
.pager-left a, .pager-right a { color: var(--text-muted); font-size: 0.8rem; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }

/* Related Posts */
.related-postbwrap { background: transparent !important; }
.related-postbwrap h4 { font-family: var(--font-display); font-size: 1.2rem; font-weight: 800; color: var(--text-primary); background: var(--bg-elevated) !important; border-color: var(--bg-border) !important; letter-spacing: 1px; text-transform: uppercase; }
.related-post-style-2 li { background: var(--bg-card); border: 1px solid var(--bg-border) !important; border-radius: var(--radius) !important; box-shadow: none !important; overflow: hidden; transition: all 0.3s; }
.related-post-style-2 li:hover { border-color: rgba(232,0,26,0.4) !important; transform: translateY(-3px); }
.related-post-style-2 .related-post-item-title { color: var(--text-primary) !important; font-family: var(--font-display); }
.related-post-style-2 .related-post-item-summary { color: var(--text-secondary) !important; }

/* Author box */
.authorboxwrap { background: var(--bg-elevated) !important; border-top: 1px solid var(--bg-border) !important; padding: 24px !important; }
.author_description_container h4 { color: var(--text-primary) !important; }
.author_description_container h4 span { color: var(--primary) !important; }
.author_description_container p { color: var(--text-secondary) !important; }
.avatar-container { border: 2px solid var(--primary) !important; border-radius: 50% !important; box-shadow: var(--glow-primary); }
.social-links i { background: var(--bg-card) !important; color: var(--text-secondary) !important; border: 1px solid var(--bg-border); transition: all 0.2s; }
.social-links i:hover { background: var(--primary) !important; color: #fff !important; border-color: var(--primary); }

/* Comments */
#comments { background: var(--bg-card) !important; border: 1px solid var(--bg-border) !important; border-radius: var(--radius); margin-bottom: 20px; }
#comments h4 { background: var(--bg-elevated) !important; color: var(--text-primary) !important; border-bottom: 1px solid var(--bg-border) !important; }
.comment-block { border-bottom: 1px solid var(--bg-border) !important; }
.comments .comments-content .comment-header { background: var(--bg-elevated) !important; border-color: var(--bg-border) !important; }
.comments .comments-content .comment-content { background: var(--bg-card) !important; border-color: var(--bg-border) !important; color: var(--text-secondary) !important; }
.comment-actions a { background: var(--bg-elevated) !important; border-color: var(--bg-border) !important; color: var(--primary) !important; }
.comment-actions a:hover { background: var(--primary) !important; color: #fff !important; }

/* === SIDEBAR === */
#sidebar { background: transparent !important; }
#sidebar .widget {
  background: var(--bg-card) !important;
  border: 1px solid var(--bg-border) !important;
  border-top: 2px solid var(--primary) !important;
  border-radius: var(--radius) !important;
  box-shadow: var(--shadow-card) !important;
  margin-bottom: 20px !important; overflow: hidden;
}
#sidebar .widget h2 {
  font-family: var(--font-display) !important;
  font-size: 0.8rem !important; font-weight: 800 !important;
  letter-spacing: 2px; text-transform: uppercase;
  color: var(--text-secondary) !important;
  background: var(--bg-elevated) !important;
  border-bottom: 1px solid var(--bg-border) !important;
  padding: 12px 16px !important; margin: 0 !important;
  box-shadow: none !important;
}
#sidebar .widget-content { padding: 14px !important; }

/* Popular Posts Sidebar */
.PopularPosts ul li {
  background: transparent !important; border-bottom: 1px solid var(--bg-border) !important;
  padding: 10px 0 !important; margin: 0 !important;
}
.PopularPosts ul li:last-child { border-bottom: none !important; }
.PopularPosts ul li img { border-radius: var(--radius-sm); object-fit: cover; }
.PopularPosts ul li .item-title a, .PopularPosts ul li a {
  color: var(--text-secondary) !important; font-size: 0.85rem !important;
  font-family: var(--font-body); font-weight: 500 !important;
}
.PopularPosts ul li .item-title a:hover, .PopularPosts ul li a:hover { color: var(--primary) !important; }

/* Label Cloud */
.cloud-label-widget-content .label-size a {
  background: var(--bg-elevated) !important; color: var(--text-secondary) !important;
  border: 1px solid var(--bg-border); font-size: 0.75rem !important;
  padding: 6px 10px !important; border-radius: var(--radius-sm) !important;
  transition: all 0.2s;
}
.cloud-label-widget-content .label-size:hover a {
  background: var(--primary) !important; color: #fff !important; border-color: var(--primary);
}

/* Archive widget */
#ArchiveList a.post-count-link { color: var(--text-secondary) !important; font-size: 0.85rem; }
#ArchiveList a.post-count-link:hover { color: var(--primary) !important; }
#ArchiveList select {
  width: 100%; padding: 10px; border: 1px solid var(--bg-border);
  background: var(--bg-elevated); color: var(--text-primary);
  border-radius: var(--radius-sm); font-size: 0.85rem;
}

/* === FEATURED SECTION (Homepage Label Posts) === */
.featured-area { max-width: 1080px; margin: 0 auto; padding: 0 16px; }
.mag-wrapper { background: transparent !important; }
#recent1 { width: 100%; }
#recent1 .title {
  font-family: var(--font-display) !important; font-size: 0.8rem !important;
  font-weight: 800 !important; letter-spacing: 2px; text-transform: uppercase !important;
  background: var(--primary) !important; color: #fff !important;
  padding: 10px 20px !important; border-radius: var(--radius-sm) !important;
  box-shadow: var(--glow-primary) !important; margin: 24px 0 16px !important;
  display: inline-block !important;
}
#recent1 .recent-box {
  width: 31.5% !important; background: var(--bg-card) !important;
  border: 1px solid var(--bg-border) !important; border-radius: var(--radius) !important;
  box-shadow: var(--shadow-card) !important; overflow: hidden;
  transition: all 0.3s; margin-right: 2.5% !important; margin-bottom: 16px !important;
}
#recent1 .recent-box:hover { border-color: rgba(232,0,26,0.4) !important; transform: translateY(-4px); }
#recent1 li.recent-box:nth-child(3), #recent1 li.recent-box:nth-child(6) { margin-right: 0 !important; }
#recent1 .recent-box .imageContainer { width: 100% !important; height: 180px !important; background: var(--bg-elevated) !important; }
.label_thumb { height: 180px !important; }
#recent1 .label_title {
  color: var(--text-primary) !important; font-family: var(--font-display) !important;
  font-size: 0.95rem !important; font-weight: 700 !important; padding: 12px 12px 0 !important;
}
#recent1 .label_title:hover { color: var(--primary) !important; }
.post-date { color: var(--text-muted) !important; }
.recent-com { color: var(--text-muted) !important; }

/* === FOOTER === */
#footer-wrapper {
  background: var(--bg-card) !important; margin-top: 40px;
  border-top: 1px solid var(--bg-border);
}
.footer-bottom { padding: 32px 16px !important; }
#footer-wrapper h2 { color: var(--text-primary) !important; font-family: var(--font-display) !important; font-size: 1rem !important; font-weight: 800 !important; letter-spacing: 1px; text-transform: uppercase; }
#footer-wrapper .widget-content { color: var(--text-muted) !important; font-size: 0.9rem !important; text-align: left !important; }
#footer-wrapper .widget li { background: var(--bg-elevated) !important; border: 1px solid var(--bg-border) !important; border-radius: var(--radius-sm) !important; padding: 8px 14px !important; margin: 0 6px 6px 0 !important; display: inline-block !important; }
.footer li a { color: var(--text-secondary) !important; font-size: 0.85rem !important; }
.footer li a:hover { color: var(--primary) !important; }
.textwidget { color: var(--text-secondary) !important; line-height: 1.7; font-size: 0.9rem; }
.textwidget b { color: var(--primary); font-weight: 600; }
#footerfix { background: var(--bg-deep) !important; border-top: 1px solid var(--bg-border); }
.copyleft { color: var(--text-muted) !important; font-size: 0.8rem !important; padding: 14px !important; }
.copyleft a { color: var(--primary) !important; }

/* === SCROLL TO TOP === */
.smoothscroll-top {
  position: fixed; bottom: -60px; right: 24px; z-index: 999;
  width: 44px; height: 44px; background: var(--primary);
  color: #fff; border-radius: var(--radius); border: none;
  display: flex; align-items: center; justify-content: center;
  font-size: 16px; cursor: pointer; box-shadow: var(--glow-primary);
  transition: all 0.4s ease; opacity: 0; visibility: hidden;
}
.smoothscroll-top.show { bottom: 24px; opacity: 1; visibility: visible; }
.smoothscroll-top:hover { background: var(--primary-dark); transform: translateY(-3px); }

/* === BLOCKQUOTE === */
blockquote {
  border-left: 4px solid var(--primary) !important;
  background: var(--bg-elevated); color: var(--text-secondary) !important;
  padding: 16px 20px !important; border-radius: 0 var(--radius) var(--radius) 0 !important;
  box-shadow: none !important;
}

/* === SUBSCRIBE / EMAIL === */
#wp-subscribe { background: var(--bg-elevated) !important; border-radius: var(--radius); padding: 20px !important; }
#wp-subscribe h4.title { color: var(--primary) !important; }
#wp-subscribe input.email-field { background: var(--bg-card) !important; color: var(--text-primary) !important; border-color: var(--bg-border) !important; box-shadow: none !important; }
#wp-subscribe input.submit { background: var(--primary) !important; }

/* === ANIMATIONS === */
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}
.animated.fadeInUp, .animated.fadeInUpBig { animation: fadeInUp 0.5s ease forwards; }
.fade-in { opacity: 0; animation: fadeInUp ease-in 1; animation-fill-mode: forwards; animation-duration: 0.8s; }
.fade-in.one { animation-delay: 0.3s; }
.fade-in.two { animation-delay: 0.6s; }
.fade-in.three { animation-delay: 0.9s; }

/* === RESPONSIVE === */
@media (max-width: 960px) {
  .bwrapsite-content { flex-direction: column; }
  .sidebar-area { width: 100% !important; }
  .content-area { width: 100% !important; }
  .navbar-inner { flex-wrap: wrap; height: auto; padding: 12px 16px; gap: 10px; }
  #main-nav { width: 100%; display: none; }
  #main-nav.open { display: flex; flex-direction: column; }
  #main-nav .menu { flex-direction: column; width: 100%; }
  #main-nav > .menu > li > a { width: 100%; }
  #menu-icon { display: flex; }
  input#sq { width: 100%; }
  #search-bar { width: 100%; }
}
@media (max-width: 768px) {
  .post-outer { width: 100% !important; margin-right: 0 !important; }
  .channels .channel-list { grid-template-columns: repeat(2, 1fr); }
  #recent1 .recent-box { width: 48% !important; margin-right: 2% !important; }
  h1.post-title { font-size: 1.4rem !important; }
  .pager-left, .pager-right { width: 100% !important; margin-bottom: 10px; }
  .sharepost li { width: 45% !important; margin-bottom: 8px; }
}
@media (max-width: 480px) {
  .channels .channel-list { grid-template-columns: 1fr; }
  #recent1 .recent-box { width: 100% !important; margin-right: 0 !important; }
  .smoothscroll-top { right: 12px; bottom: 12px; }
  .sharepost li { width: 100% !important; }
  .m-col { flex-wrap: wrap; gap: 8px; }
}

