body.script:
//
// Mobile menu toggle
document.getElementById('menu-icon') && document.getElementById('menu-icon').addEventListener('click', function(){
  var nav = document.getElementById('main-nav');
  nav.classList.toggle('open');
  this.classList.toggle('active');
});

// Scroll to top
$(window).scroll(function(){
  if($(window).scrollTop()>120){$('.smoothscroll-top').addClass('show');}
  else{$('.smoothscroll-top').removeClass('show');}
});
function scrollToTop(){$('html,body').animate({scrollTop:0},600,'linear');}

// Preloader
$(window).on('load',function(){$('#preloader').fadeOut(600);});

// Popular post snippet trim
$(".popular-posts ul li .item-snippet").each(function(){var t=$(this).text().substr(0,40),s=t.lastIndexOf(" ");s>32&&$(this).text(t.substr(0,s).replace(/[?,!\.-:;]*$/,"..."))});
$(".item-thumbnail img").each(function(){$(this).attr("src",$(this).attr("src").replace(/\/s[0-9]+(\-c)?\//,"/w100-h80-c/"))});

